-- ================================================================
-- Seed File: العملاء — النسخة المُصلَحة v2
-- المصدر   : العملاء (2).xlsx
-- إجمالي  : 1860 عميل (234 بدون كود)
-- IDEMPOTENT: آمن للتشغيل مرات متعددة
--   • عملاء بكود    → ON CONFLICT (code) DO UPDATE
--   • عملاء بدون كود → WHERE NOT EXISTS (old_id في notes)
-- ================================================================

BEGIN;

-- ────────────────────────────────────────────────────────────
-- 1. إضافة المدن الجديدة
-- ────────────────────────────────────────────────────────────
DO $$
DECLARE v_gov_id UUID;
BEGIN
  SELECT id INTO v_gov_id FROM governorates WHERE code = '05';
  IF v_gov_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM cities WHERE governorate_id = v_gov_id AND name = 'كوم حمادة'
  ) THEN
    INSERT INTO cities (governorate_id, name, sort_order)
    VALUES (v_gov_id, 'كوم حمادة', 99);
  END IF;
END; $$;

DO $$
DECLARE v_gov_id UUID;
BEGIN
  SELECT id INTO v_gov_id FROM governorates WHERE code = '08';
  IF v_gov_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM cities WHERE governorate_id = v_gov_id AND name = 'شبرا النملة'
  ) THEN
    INSERT INTO cities (governorate_id, name, sort_order)
    VALUES (v_gov_id, 'شبرا النملة', 99);
  END IF;
END; $$;

-- ────────────────────────────────────────────────────────────
-- 2. العملاء (1860 صف)
-- ────────────────────────────────────────────────────────────

