WHERE (SELECT id FROM customers WHERE code = 'CUS-00056' LIMIT 1) IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM customer_contacts cc
    WHERE cc.customer_id=(SELECT id FROM customers WHERE code = 'CUS-00056' LIMIT 1) AND cc.name='سامح'
  );

